  ('investigation-2b298e71-moex-00157', 'investigation-2b298e71', 'investigation-2b298e71-moex-110-de0a21a2', 'sub-investigation-2b298e71-01', NULL, 'essay', '甲男以狗繩牽著飼養多年的狼犬小黑至公園散步，途中遇到素有嫌隙的
鄰居乙男，兩人為了平常的鄰居糾紛爭吵起來。因兩人越吵越兇，手勢
激烈，致小黑誤以為乙要攻擊甲，小黑護主心切，遂掙脫甲手中的狗繩
撲前攻擊乙。由於小黑力量龐大，甲無法操控繫住其之狗繩，故而無法
阻止小黑攻擊乙。甲見小黑已經將乙撲倒在地並不斷撕咬，有可能將乙
咬死，且若自己出面安撫小黑，可使小黑停止攻擊，但因兩人平常結怨
已深，故放任小黑繼續攻擊乙。渾身鮮血的乙疼痛不已，厲聲揚言做鬼
也不會放過甲，甲方驚覺事態嚴重，連忙令小黑停止攻擊，並至路邊撥
打 119召喚救護車。此時乙已經失血過多，若不送醫急救，必死無疑。
惟在甲電召之救護車來之前，一旁圍觀的路人丙主動將乙送往醫院急
救，乙經大量輸血後撿回一命。試問甲有何刑責？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:52+00:00", "source_pdf_sha1": "e3953f7a9f61", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "404", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "調查工作組"}'::jsonb, NULL)
